class Solution:
    def findLucky(self, arr):
        best = -1
        for v in set(arr):
            if arr.count(v) == v:
                best = max(best, v)
        return best

solutions.python:
class Solution:
    def findLucky(self, arr):
        from collections import Counter
        freq = Counter(arr)
        best = -1
        for v, c in freq.items():
            if v == c:
                best = max(best, v)
        return best

