var findLucky = function(arr) {
    const freq = new Map();
    for (const x of arr) freq.set(x, (freq.get(x) || 0) + 1);
    let best = -1;
    for (const [v, c] of freq) {
        if (v === c) best = Math.max(best, v);
    }
    return best;
};
